{
  "mode": "method",
  "tests": [
    {
      "name": "valid_user_with_active_challenges",
      "input": {
        "userId": "user123",
        "role": "reviewer"
      },
      "output": [
        {
          "challengeId": "challenge1",
          "status": "ACTIVE",
          "userRole": "reviewer",
          "reviewId": "review1"
        },
        {
          "challengeId": "challenge2",
          "status": "ACTIVE",
          "userRole": "reviewer",
          "reviewId": "review2"
        }
      ],
      "notes": "Tests the scenario where a user with the reviewer role has active challenges."
    },
    {
      "name": "valid_user_with_no_active_challenges",
      "input": {
        "userId": "user456",
        "role": "reviewer"
      },
      "output": [],
      "notes": "Tests the scenario where a user has no active challenges."
    },
    {
      "name": "user_with_inactive_challenges",
      "input": {
        "userId": "user789",
        "role": "reviewer"
      },
      "output": [],
      "notes": "Tests the scenario where a user has only inactive challenges."
    },
    {
      "name": "user_with_multiple_roles",
      "input": {
        "userId": "user101",
        "role": "submitter"
      },
      "output": [
        {
          "challengeId": "challenge3",
          "status": "ACTIVE",
          "userRole": "submitter",
          "reviewId": "review3"
        }
      ],
      "notes": "Tests the scenario where a user has multiple roles but only one active review as a submitter."
    },
    {
      "name": "user_with_no_reviews",
      "input": {
        "userId": "user202",
        "role": "reviewer"
      },
      "output": [],
      "notes": "Tests the scenario where a user exists but has no reviews assigned."
    },
    {
      "name": "invalid_user_id",
      "input": {
        "userId": "invalidUser",
        "role": "reviewer"
      },
      "output": "User not found",
      "notes": "Tests the scenario where an invalid user ID is provided."
    },
    {
      "name": "user_with_pending_reviews",
      "input": {
        "userId": "user303",
        "role": "reviewer"
      },
      "output": [
        {
          "challengeId": "challenge4",
          "status": "ACTIVE",
          "userRole": "reviewer",
          "reviewId": "review4"
        }
      ],
      "notes": "Tests the scenario where a user has pending reviews for active challenges."
    },
    {
      "name": "user_with_role_mismatch",
      "input": {
        "userId": "user404",
        "role": "submitter"
      },
      "output": [],
      "notes": "Tests the scenario where a user role does not match any active reviews."
    }
  ],
  "assumptions": "User IDs are unique and valid. Challenges can be either active or inactive.",
  "notes": "Ensure that the integration with Challenge API and Resources API is functioning correctly."
}
